<#
.SYNOPSIS
    rmdotnet
#>
Write-Host "PURGING .NET INSTALLATIONS (KEEPING v8 and v9)..." -ForegroundColor Red; $dotnetPackages = @("Microsoft.DotNet.SDK.Preview", "Microsoft.DotNet.SDK.7", "Microsoft.DotNet.SDK.6", "Microsoft.DotNet.SDK.5", "Microsoft.DotNet.SDK.3_1", "Microsoft.DotNet.Runtime.Preview", "Microsoft.DotNet.Runtime.7", "Microsoft.DotNet.Runtime.6", "Microsoft.DotNet.Runtime.5", "Microsoft.DotNet.Runtime.3_1", "Microsoft.DotNet.DesktopRuntime.Preview", "Microsoft.DotNet.DesktopRuntime.7", "Microsoft.DotNet.DesktopRuntime.6", "Microsoft.DotNet.DesktopRuntime.5", "Microsoft.DotNet.DesktopRuntime.3_1", "Microsoft.DotNet.AspNetCore.Preview", "Microsoft.DotNet.AspNetCore.7", "Microsoft.DotNet.AspNetCore.6", "Microsoft.DotNet.AspNetCore.5", "Microsoft.DotNet.AspNetCore.3_1", "Microsoft.DotNet.WindowsHosting.Preview", "Microsoft.DotNet.WindowsHosting.7", "Microsoft.DotNet.WindowsHosting.6", "Microsoft.DotNet.WindowsHosting.5", "Microsoft.DotNet.WindowsHosting.3_1", "Microsoft.DotNet.Framework.DeveloperPack_4"); foreach($pkg in $dotnetPackages) { Write-Host "Removing: $pkg" -ForegroundColor Yellow; winget uninstall --id $pkg --silent --force 2>$null }; Write-Host "CLEANING DIRECTORIES (PRESERVING v8 and v9)..." -ForegroundColor Cyan; $pathsToClean = @("$env:ProgramFiles(x86)\Reference Assemblies\Microsoft\Framework\.NETFramework\v4.0", "$env:ProgramFiles(x86)\Reference Assemblies\Microsoft\Framework\.NETFramework\v4.5*", "$env:ProgramFiles(x86)\Reference Assemblies\Microsoft\Framework\.NETFramework\v4.6*", "$env:ProgramFiles(x86)\Reference Assemblies\Microsoft\Framework\.NETFramework\v4.7*", "$env:USERPROFILE\.nuget\packages", "$env:LOCALAPPDATA\NuGet\v3-cache", "$env:APPDATA\NuGet", "$env:TEMP\dotnet*", "$env:TEMP\NuGet*"); foreach($path in $pathsToClean) { if(Test-Path $path) { Write-Host "Deleting: $path" -ForegroundColor Red; Remove-Item $path -Recurse -Force -ErrorAction SilentlyContinue } }; Write-Host "CLEANING ENVIRONMENT (PRESERVING v8 and v9 PATHS)..." -ForegroundColor Magenta; $currentPath = [Environment]::GetEnvironmentVariable("PATH", "Machine"); $cleanPath = ($currentPath -split ';' | Where-Object { $_ -notmatch "dotnet.*[3-7]\.|dotnet.*Preview|\.NET.*[3-7]\." }) -join ';'; [Environment]::SetEnvironmentVariable("PATH", $cleanPath, "Machine"); $currentUserPath = [Environment]::GetEnvironmentVariable("PATH", "User"); $cleanUserPath = ($currentUserPath -split ';' | Where-Object { $_ -notmatch "dotnet.*[3-7]\.|dotnet.*Preview|\.NET.*[3-7]\." }) -join ';'; [Environment]::SetEnvironmentVariable("PATH", $cleanUserPath, "User"); Write-Host "CLEANING TEMP FILES..." -ForegroundColor Green; Get-ChildItem $env:TEMP -Filter "*dotnet*" -ErrorAction SilentlyContinue | Where-Object { $_.Name -notmatch "[89]\." } | Remove-Item -Recurse -Force -ErrorAction SilentlyContinue; Get-ChildItem $env:TEMP -Filter "*NuGet*" -ErrorAction SilentlyContinue | Remove-Item -Recurse -Force -ErrorAction SilentlyContinue; Write-Host "SELECTIVE PURGE COMPLETE - VERIFICATION:" -ForegroundColor Green; Write-Host "Remaining .NET packages:" -ForegroundColor Yellow; winget list | Where-Object { $_ -match "Microsoft\.DotNet\." }; Write-Host "Dotnet command check:" -ForegroundColor Yellow; if(Get-Command dotnet -ErrorAction SilentlyContinue) { Write-Host "dotnet still available (v8/v9 preserved)" -ForegroundColor Green; Write-Host "REMAINING .NET VERSIONS:" -ForegroundColor Cyan; Write-Host "=== .NET INFO ===" -ForegroundColor White; dotnet --info; Write-Host "=== INSTALLED SDKs ===" -ForegroundColor Yellow; dotnet --list-sdks; Write-Host "=== INSTALLED RUNTIMES ===" -ForegroundColor Magenta; dotnet --list-runtimes } else { Write-Host "dotnet command not found" -ForegroundColor Red }; Write-Host "Directory check:" -ForegroundColor Yellow; if(Test-Path "$env:ProgramFiles\dotnet") { Write-Host ".NET directory preserved (v8/v9)" -ForegroundColor Green; $dotnetSize = (Get-ChildItem "$env:ProgramFiles\dotnet" -Recurse -ErrorAction SilentlyContinue | Measure-Object -Property Length -Sum).Sum / 1GB; Write-Host "Current .NET installation size: $([math]::Round($dotnetSize, 2)) GB" -ForegroundColor Cyan } else { Write-Host ".NET directory not found" -ForegroundColor Red }; Write-Host "ESTIMATED SPACE FREED: ~1-3 GB (older versions removed)" -ForegroundColor Green; Write-Host ".NET 8 and 9 installations preserved!" -ForegroundColor Green
